    function fnPrintHits() {
        var strSelValue = "2017/09/28-1;";
        //전체전표 인쇄시
        if (strSelValue == "" && "" != "") 
        {
            strSelValue = "";
        }

        var splitdata = strSelValue.split(";");
        var strTrxData;
        var strTrxDATE;
        var strFormGubun;
        var strSlipTrxType;
        var strSlipSerNo;

        for ( var i = 0; i < splitdata.length-1; i++)
        {
            strTrxData = splitdata[i].split("-");
            strTrxDATE = strTrxData[0].split("/");  
            
            if(strTrxData.length > 3){
                //리스트에서 선택인쇄시 파라미터 값으로 전표타입구분
                strSlipTrxType = strTrxData[3];

                if(strSlipTrxType.toUpperCase() == "CASE94")
                    strFormGubun = "AF040";    //지출결의서
                else if(strSlipTrxType.toUpperCase() == "CASE93")
                    strFormGubun = "AF050";     //입금보고서
                else if(strSlipTrxType.toUpperCase() == "CASE92")
                    strFormGubun = "AF060";     //가지급금정산서
                else
                    strFormGubun = "AF070";
            }else{
                //입력화면에서 저장및전표인쇄시
                strSlipTrxType = "98";
                strSlipSerNo = "01";

                if(strSlipTrxType == "98" && strSlipSerNo == "04")
                    strFormGubun = "AF040";    //지출결의서
                else if(strSlipTrxType == "98" && strSlipSerNo == "05")
                    strFormGubun = "AF050";     //입금보고서
                else if(strSlipTrxType == "98" && strSlipSerNo == "06")
                    strFormGubun = "AF060";     //가지급금정산서
                else
                    strFormGubun = "AF070";
            }

            //지출결의서, 입금보고서인쇄에서 전표인쇄, 건별전표인쇄일 경우 재정의
            if("N" =="Y")
                strFormGubun ="AF100";//건별전표인쇄
//            else
//                strFormGubun ="AF070"; //전표인쇄

            var strData = "FORM_GUBUN="+strFormGubun+"&IO_DATE="+ strTrxDATE[0] +strTrxDATE[1] + strTrxDATE[2] + "&IO_NO="+strTrxData[1]+"&CS_FLAG=N";

            $.ajax({
                type: "POST",
                async: false,
                url: fnSetUrlPath("/ECMain/ESD/ESD006M_DATA.aspx", "ec_req_sid"),
                data: strData,
                error: function(errorMsg) {
                    alert("에러발생"+"\nfnGetData:" + errorMsg);
                    return false; 
                },
                success: function(returnXml) {
                }
            });
        }

        //fnPrintBeforeWork();
        var url = "/ECMain/EBZ/EBZ013P_01.aspx?print_flag=Y";
        if ($("#form_ser").get(0) != undefined)
            url += "&form_ser=" + $("#form_ser").get(0).value;
        $("#hidSelV1").get(0).value = strSelValue;
        window.open('about:blank', 'orderprint1', 'left=50000,top=50000,width=0,height=0');
	    $("#frmDetail").get(0).method = "post";
	    $("#frmDetail").get(0).target = "orderprint1";
	    $("#frmDetail").get(0).action = fnSetUrlPath(url,'ec_req_sid');
	    $("#frmDetail").submit();
        //printURL2("", "N");
        return false; 
    }

