    //출력시 사전 작업
    function fnPrintBeforeWork() {

        //인쇄시 1장넘는 내용 page-break 적용되게하는 변수 생성 virtualpage 에 height를 입력
        //hidheightParam는 printLoadPage2.aspx에서 작동됨
        //window.setTimeout(function () {
        var divHeightParam="";
        if ($(".virtualpage[printtype=page]").length > 0) {
            $(".hidepiece").removeClass("hidepiece");
            $(".virtualpage[printtype=page]").each(function (index) {
                var divHeight = 0;
                var objpabsolute = $(this).find(".p-absolute:last");
                var divposition = objpabsolute.position();
                divHeight = objpabsolute.outerHeight();
                divHeight = divHeight + divposition.top;                   
                $(this).addClass("hidepiece")

                if (divHeight > 0) {
                    $(this).css("height", divHeight);
                }
                divHeightParam = divHeightParam + divHeight.toString() + ";"
            });

            $('#hidHeightParam').get(0).value = divHeightParam;
        }
           //}, 0);
    }

    // 페이징 설정 부분
    var pagecontent = new virtualpaginate({
        piececlass: "virtualpage", //class of container for each piece of content
        piececontainer: "div", //container element type (ie: "div", "p" etc)
        pieces_per_page: 1, //Pieces of content to show per page (1=1 piece, 2=2 pieces etc)
        defaultpage: 0, //Default page selected (0=1st page, 1=2nd page etc). Persistence if enabled overrides this setting.
        wraparound: false,
        persist: false //Remember last viewed page and recall it when user returns within a browser session?
    })

    pagecontent.buildpagination(["scriptspaginate"]);

    // 마우스 힐로 페이징 처리 부분
    $('#dual_btn_area').bind('mousewheel', function (e) {
        if (e.originalEvent.wheelDelta < 0) {
            pagecontent.navigate("next");
        } else {
            pagecontent.navigate("previous");
        }
        return false;
    });

    if ($(".virtualpage").length < 2) {
        $("#dual_btn_area").css("display", "none");
    }

