        var buttonName;

        switch (flag) {
            case '1' :
                buttonName = '청구서';
                break;
            case '2' :
                buttonName = '거래명세서';
                break;
            case '3' :
                buttonName = '구매전표';
                break;
            case '4' :
                buttonName = '입금표';
                break;
        }
        
        if (buttonName) {
            var param = { "TYPE": "회계인쇄버튼", "TXT": buttonName, "TXT2": "EBZ013P_01.aspx" };
            $.ajax({
	            type: "POST",
	            dataType: "json",
	            data: JSON.stringify(param),
	            contentType: 'application/json',
	            async:false,
	            url: fnSetUrlPath("/ECAPI/Common/Infra/InsertUseCntHistoryTxt", "ec_req_sid"),        
	            error: function(errorMsg) {
		            alert('error');
	            }
            });
        }
    }

